1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	type QuoteResult = { premium: number };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	
9	const ITEM_BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const BLOCK_SIZE = 3;
19	const BLOCK_BASE_PREMIUM = 60;
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	const CURSE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	
26	const sumBy = <T>(items: T[], f: (x: T) => number): number =>
27	  items.reduce((acc, x) => acc + f(x), 0);
28	
29	const baseFor = (item: Item): number => ITEM_BASE_PREMIUMS[item.type];
30	
31	const SURCHARGE_RULES: ReadonlyArray<{ applies: (item: Item) => boolean; rate: number }> = [
32	  { applies: (item) => item.cursed === true, rate: CURSE_RATE },
33	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_RATE },
34	];
35	
36	const surchargeFor = (item: Item): number => {
37	  const base = baseFor(item);
38	  return sumBy(SURCHARGE_RULES, (rule) => (rule.applies(item) ? base * rule.rate : 0));
39	};
40	
41	const totalSurchargeFor = (items: Item[]): number => sumBy(items, surchargeFor);
42	
43	const premiumFor = (totalBase: number, totalSurcharge: number): number =>
44	  totalBase + totalSurcharge + Math.ceil(totalBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
45	
46	const groupByType = (items: Item[]): Map<string, Item[]> => {
47	  const groups = new Map<string, Item[]>();
48	  for (const item of items) {
49	    const group = groups.get(item.type) ?? [];
50	    group.push(item);
51	    groups.set(item.type, group);
52	  }
53	  return groups;
54	};
55	
56	const baseForGroup = (type: string, group: Item[]): number => {
57	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
58	  return sumBy(group, baseFor);
59	};
60	
61	const totalBaseFor = (items: Item[]): number =>
62	  Array.from(groupByType(items)).reduce(
63	    (total, [type, group]) => total + baseForGroup(type, group),
64	    0,
65	  );
66	
67	const quoteFor = (step: QuoteStep): QuoteResult => ({
68	  premium: premiumFor(totalBaseFor(step.items), totalSurchargeFor(step.items)),
69	});
70	
71	export const processScenario = (input: Scenario): { results: QuoteResult[] } => {
72	  return { results: input.steps.map(quoteFor) };
73	};
